1	type Cell = [number, number];
2	
3	const countNeighbors = (cell: Cell, cells: Cell[]): number =>
4	  cells.filter((candidate) =>
5	    Math.max(
6	      Math.abs(candidate[0] - cell[0]),
7	      Math.abs(candidate[1] - cell[1])
8	    ) === 1
9	  ).length;
10	
11	export function nextGeneration(cells: Cell[]): Cell[] {
12	  return cells.filter((cell) => {
13	    const neighborCount = countNeighbors(cell, cells);
14	    return neighborCount === 2 || neighborCount === 3;
15	  });
16	}
